defmodule MyAppWeb.UserController do
  use Phoenix.Controller
  
  alias Ecto.Changeset
  import Plug.Conn
    
  plug :put_layout, "admin/app.html" when action in [:edit] and method in ["GET", "POST"]
      
    def update(conn, %{"id" => id} = params) do  
      user =  MyApp.Repo.getUserById(id)  # assuming you have a function get_user by ID to fetch the User from database    
        
        changeset  = Ecto.Changeset.change_schema(%MyApp.User{}, %{"name" => params["name"], "email"=>params['email']})  
          
      case Changeset.apply_changes(changeset) do  # apply the updates to user model   
        {:ok, updated} ->    
          MyApp.Repo.updateUserByIdAndReturnUpdatedData(user ,updated )# assuming you have a function update by ID and return data  
           conn |>  put_flash(:info, "Successfully Updated User.")  |>  redirect(to: Routes.admin_path(conn, :index))  #redirect to index after successful operation   
        {:error, changeset} ->    
          render (conn ,"edit", user: updated)  |  conn |>  put_flash(:info, "Error updating User.")  |>  redirect(to: Routes.admin_path(conn, :index))  #redirect to index after error   
      end       
      
     defp authorized?(_), do: true         # server side authorization check for each resource  
end